const presetName = "seaAnemone";
export async function loadSeaAnemonePreset(engine) {
    await engine.pluginManager.register(async (e) => {
        const [{ loadBasic }, { loadEmittersPluginSimple }, { loadTrailPlugin }, { loadCurvesPath }, { options },] = await Promise.all([
            import("@tsparticles/basic/lazy"),
            import("@tsparticles/plugin-emitters/plugin/lazy"),
            import("@tsparticles/plugin-trail/lazy"),
            import("@tsparticles/path-curves/lazy"),
            import("./options.js"),
        ]);
        await Promise.all([
            (async () => {
                await loadBasic(e);
                await loadCurvesPath(e);
            })(),
            loadEmittersPluginSimple(e),
            loadTrailPlugin(e),
        ]);
        e.pluginManager.addPreset(presetName, options);
    });
}
